import React from 'react';
import './Navbar.css';
import {useRef, useState, useEffect} from 'react';

const Navbar = () => {

    const [isSticky, setSticky] = useState(false)
    const ref = useRef(null)

    useEffect(() => {
        const cachedRef = ref.current,
            observer = new IntersectionObserver(
                ([e]) => setSticky(e.intersectionRatio < 1),
                {threshold: [1]}
            )
        observer.observe(cachedRef)

        return function(){
            observer.unobserve(cachedRef)
        }
    }, [])
    // add a _ in front of classname in navbar to apply 2 classes
    //<div className={"Navbar" + (isSticky === true ? " isSticky" : "")} ref={ref} >

    //create new css classes dependent on isSticky
    console.log(isSticky);
    return(
        <div className={"Navbar" + (isSticky ? " isSticky" : "")} ref={ref} >
            <div className='NavbarText'>
                <a className="Navbarbutton" href="#Header">Home</a>
                <a className="Navbarbutton" href="#MainContent">Info</a>
                <a className="Navbarbutton" href="#Cv">CV</a>
                <a className="Navbarbutton" href="#Projects">Latest Projects</a>
            </div>
        </div>
    )
}


export default Navbar;