import React, {useState, useEffect} from 'react';
import './Cv.css';
import './CV.docx';


import {useTrail, animated} from 'react-spring';

//make a toggle for each h1 that uses trail to render the info from cv 

const School = [
    "Gymnasie - Data",
    "Gymnasie - Betongare",
    "Universitet - Ljuddesigner",
    "Distans - Webutveckling",
    "Distans - Dataanalys"
]
const Work = [
    "Betongarbetare - asplunds bygg",
    "Telekommunikatör - Tele2 Karlskoga",
    "Telekommunikatör - Tele2 Stockholm",
    "Larmoperatör - Bergslagens Räddningstjänst"
]
const Experience = [
    ['React', 65],
    ['Node', 40],
    ['Python', 65],
    ['Html / Css', 80],
    ['Javascript', 75],
    ['Swift', 15],
]

const Progress = ({done}) => {

    const [style, setStyle] = useState({})
    
    useEffect(() => {
        let timer = setTimeout(() => {
            const newStyle = {
                
                opacity: 1,
                width: `${done}%`,
                
            }
    
            setStyle(newStyle);
        }, 500);

        return () => {
            clearTimeout(timer);
        }
        
    }, [done])

    //sending back [done] in useffect 
    //and returning clearTimeout in the cleanup funciton solved memoryleak 

    

    return (
        <div className="Progress">
            <div className="ProgressDone" style={style}>
                {done}%
            </div>

        </div>
    )
}

const config = {mass: 10, tension: 1000, friction: 100}

const Cv = () => {

    const [schoolToggle, setSchoolToggle] = useState(false)
    const [workToggle, setWorkToggle] = useState(false)
    const [expToggle, setExpToggle] = useState(false)

    const trail = useTrail(School.length, {
        config,
        opacity: schoolToggle ? 1 : 0,
        x: schoolToggle ? 20 : 0,
        
        from: {opacity: 0, x: 20}, 
    })
    //removing height and width from animation fixed the lag
    const trail2 = useTrail(Work.length, {
        config,
        opacity: workToggle ? 1 : 0,
        x: workToggle ? 20 : 0,
        
        from: {opacity: 0, x: 20}, 
    })

    const trail3 = useTrail(Experience.length, {
        config,
        opacity: expToggle ? 1 : 0,
        x: expToggle ? 20 : 0,
        
        from: {opacity: 0, x: 20}, 
    })

    const schoolToggleTrue = () => setSchoolToggle(!schoolToggle)
    const workToggleTrue = () => setWorkToggle(!workToggle)
    const expToggleTrue = () => setExpToggle(!expToggle)

    return (
        <div className="CvContainer" id="Cv">
            <div className="CvHeader">
                <h1>CV</h1>
                <a className="CvDownload" href="CV.docx" download="KristofferErikssonCV.docx">Download full CV</a>
            </div>
            <div className="CvInfo">
                <div className="CvSchool">
                    <h1 onClick={schoolToggleTrue}>School</h1>
                    <div className="CvSchoolElements">
                        {trail.map(({ x, height, ...rest }, index) => (
                            <animated.div
                                key={School[index]}
                                className="CvInfoText"
                                style={{ ...rest, transform: x.interpolate(x => `translate3d(${x}px,${x}px,${x}px)`) }}>
                            <animated.div style={{ height }}>{School[index]}</animated.div>
                            </animated.div>
                        ))}
                    </div>
                </div>
                <div className="CvWork" >
                    <h1 onClick={workToggleTrue}>Work</h1>
                    <div className="CvWorkElements">
                        {trail2.map(({ x, height, ...rest }, index) => (
                            <animated.div
                                key={Work[index]}
                                className="CvInfoText"
                                style={{ ...rest, transform: x.interpolate(x => `translate3d(0,${x}px,0)`) }}>
                            <animated.div style={{ height }}>{Work[index]}</animated.div>
                            </animated.div>
                        ))}
                    </div>
                </div>
                <div className="CvExperience">
                    <h1 onClick={expToggleTrue}>Experience</h1>
                    <div className="CvExperienceElements">
                        {trail3.map(({ x, height, ...rest }, index) => (
                            <animated.div
                                key={Experience[index]}
                                className="CvInfoText"
                                style={{ ...rest, transform: x.interpolate(x => `translate3d(0, ${x}px, 0)`) }}>
                                <animated.div style={{ height }}>{Experience[index][0]}</animated.div>
                                {expToggle ? <Progress done={Experience[index][1]}/> : null }
                                
                            </animated.div>
                            
                        ))}
                    </div>
                    
                </div>
            </div>
        </div>
    )


}

export default Cv;